+        if (_newPassword.Length < 8)
+        {
+            _error = "New password must be at least 8 characters.";
+            return;
+        }
+
+        _saving = true;
+        try
+        {
+            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
+            _success = "Password updated successfully.";
+            _currentPassword = "";
+            _newPassword = "";
+            _confirmPassword = "";
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
