@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

@if (Visible && Session is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="OnCancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <ul class="list-unstyled mb-0">
                        <li><strong>Device:</strong> @Session.Device</li>
                        <li><strong>Location:</strong> @Session.Location</li>
                        <li><strong>Last active:</strong> @Session.LastActive.ToString("g")</li>
                    </ul>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter, EditorRequired] public EventCallback OnConfirm { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }
}

@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="table-responsive">
    <table class="table table-hover align-middle mb-0">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th class="text-end">Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td class="text-end">
                        @if (session.Id == CurrentSessionId)
                        {
                            <span class="badge bg-success">Current</span>
                        }
                        else
                        {
                            <button class="btn btn-outline-danger btn-sm"
                                    @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

