@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Profile</h4>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4 text-center">
                <div class="mb-3">
                    <label class="form-label">Avatar Preview</label>
                    <div class="mb-2">
                        @if (!string.IsNullOrEmpty(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle"
                                 style="width: 120px; height: 120px; object-fit: cover;"
                                 @onerror="() => _avatarBroken = true" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center mx-auto"
                                 style="width: 120px; height: 120px;">
                                <span class="text-white fs-1">👤</span>
                            </div>
                        }
                    </div>
                    <input type="text" class="form-control form-control-sm" placeholder="Avatar URL"
                           @bind="_avatarUrl" />
                </div>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="HandleDiscard" disabled="@(!HasChanges)">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _avatarBroken;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool HasChanges =>
        _displayName != Profile.DisplayName ||
        _email != Profile.Email ||
        _avatarUrl != Profile.AvatarUrl ||
        _bio != Profile.Bio;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            ResetFields();
        }
    }

    private void ResetFields()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task HandleSave()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void HandleDiscard()
    {
        ResetFields();
        _statusMessage = null;
    }
}

@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Notifications</h4>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show py-2">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <h6 class="text-muted mb-3">Notification Channels</h6>

        <div class="mb-3">
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <hr />

        <h6 class="text-muted mb-3">Muted Channels</h6>
        <div class="mb-3">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel @if (isMuted) { <span class="badge bg-warning text-dark ms-1">Muted</span> }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _allChannels = [.. Prefs.MutedChannels];
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                [.. _mutedChannels]);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Security</h4>
    </div>

    <!-- Change Password -->
    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card-body border-top">
        <!-- Two-Factor Authentication -->
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (Settings.TwoFactorEnabled)
                    {
                        <span class="text-success">✅ Enabled</span>
                    }
                    else
                    {
                        <span class="text-warning">⚠️ Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox"
                       checked="@Settings.TwoFactorEnabled"
                       @onchange="e => OnToggle2FA.InvokeAsync((bool)e.Value!)" />
            </div>
        </div>

        @if (Settings.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-3">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="card-body border-top">
        <h6 class="mb-3">Active Sessions</h6>
        <ActiveSessionsTable Sessions="Settings.Sessions"
                             CurrentSessionId="@Settings.Sessions.FirstOrDefault()?.Id ?? "")"
                             OnRevokeRequested="HandleRevokeRequested" />
    </div>
</div>

<RevokeSessionDialog Visible="_showRevokeDialog"
                     Session="_sessionToRevoke"
                     OnConfirm="HandleRevokeConfirmed"
                     OnCancel="() => { _showRevokeDialog = false; _sessionToRevoke = null; }" />

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    private void HandleRevokeRequested(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevokeConfirmed()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Appearance</h4>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show py-2">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
