<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Profile</h4>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show py-2">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4 text-center">
                <div class="mb-3">
                    <label class="form-label">Avatar Preview</label>
                    <div class="mb-2">
                        @if (!string.IsNullOrEmpty(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle"
                                 style="width: 120px; height: 120px; object-fit: cover;"
                                 @onerror="() => _avatarBroken = true" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center mx-auto"
                                 style="width: 120px; height: 120px;">
                                <span class="text-white fs-1">👤</span>
                            </div>
                        }
                    </div>
                    <input type="text" class="form-control form-control-sm" placeholder="Avatar URL"
                           @bind="_avatarUrl" />
                </div>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="HandleDiscard" disabled="@(!HasChanges)">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _avatarBroken;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool HasChanges =>
        _displayName != Profile.DisplayName ||
        _email != Profile.Email ||
        _avatarUrl != Profile.AvatarUrl ||
        _bio != Profile.Bio;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            ResetFields();
        }
    }

    private void ResetFields()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task HandleSave()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void HandleDiscard()
    {
        ResetFields();
        _statusMessage = null;
    }
}

