@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Security</h4>
    </div>

    <!-- Change Password -->
    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card-body border-top">
        <!-- Two-Factor Authentication -->
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (Settings.TwoFactorEnabled)
                    {
                        <span class="text-success">✅ Enabled</span>
                    }
                    else
                    {
                        <span class="text-warning">⚠️ Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox"
                       checked="@Settings.TwoFactorEnabled"
                       @onchange="e => OnToggle2FA.InvokeAsync((bool)e.Value!)" />
            </div>
        </div>

        @if (Settings.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-3">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="card-body border-top">
        <h6 class="mb-3">Active Sessions</h6>
        <ActiveSessionsTable Sessions="Settings.Sessions"
                             CurrentSessionId="@Settings.Sessions.FirstOrDefault()?.Id ?? "")"
                             OnRevokeRequested="HandleRevokeRequested" />
    </div>
</div>

<RevokeSessionDialog Visible="_showRevokeDialog"
                     Session="_sessionToRevoke"
                     OnConfirm="HandleRevokeConfirmed"
                     OnCancel="() => { _showRevokeDialog = false; _sessionToRevoke = null; }" />

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    private void HandleRevokeRequested(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevokeConfirmed()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings

<div class="card">
    <div class="card-header">
        <h4 class="mb-0">Appearance</h4>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show py-2">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-6">
                <h6 class="text-muted mb-2">Live Preview</h6>
                <div class="border rounded @PreviewBgClass" style="@PreviewStyle">
                    <div class="@PreviewPaddingClass">
                        <h6 style="@PreviewFontStyle" class="@PreviewTextClass">Sample Heading</h6>
                        <p style="@PreviewFontStyle" class="@PreviewTextClass mb-2">
                            This is how your content will look with the selected settings.
                        </p>
                        <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
                        <div class="mt-2">
                            <span class="badge @PreviewBadgeClass">Status</span>
                            <span class="ms-1 @PreviewTextClass" style="@PreviewFontStyle">
                                @_language · @_fontSize · @_theme
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    // Preview computed properties
    private string PreviewBgClass => _theme == "Dark" ? "bg-dark" : "bg-light";
    private string PreviewTextClass => _theme == "Dark" ? "text-light" : "text-dark";
    private string PreviewButtonClass => _theme == "Dark" ? "btn-outline-light" : "btn-outline-dark";
    private string PreviewBadgeClass => _theme == "Dark" ? "bg-light text-dark" : "bg-dark text-light";
    private string PreviewPaddingClass => _compactMode ? "p-2" : "p-3";

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem; min-height: 180px;",
        "Large" => "font-size: 1.15rem; min-height: 180px;",
        _ => "font-size: 1rem; min-height: 180px;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85em;",
        "Large" => "font-size: 1.15em;",
        _ => "font-size: 1em;"
    };

    private async Task HandleSave()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

