@page "/settings"
@namespace sv_060fa0c969e2427eb2e78d14ce109459.Components.Pages.Settings
@using sv_060fa0c969e2427eb2e78d14ce109459.Models
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <aside class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionChanged="section => _activeSection = section" />
    </aside>

    <section class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile!"
                                    OnSave="HandleSaveProfile" />
                    break;

                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs!"
                                          OnSave="HandleSaveNotifications" />
                    break;

                case "Security":
                    <SecuritySection Settings="_security!"
                                     OnChangePassword="HandleChangePassword"
                                     OnRevokeSession="HandleRevokeSession"
                                     OnToggle2FA="HandleToggle2FA" />
                    break;

                case "Appearance":
                    <AppearanceSection Settings="_appearance!"
                                       OnSave="HandleSaveAppearance" />
                    break;
            }
        }
    </section>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifsTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task HandleSaveProfile(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
    }

    private async Task HandleSaveNotifications(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notificationPrefs = updated;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleToggle2FA(bool enabled)
    {
        // In a real app this would call a dedicated 2FA service endpoint
        _security = _security! with { TwoFactorEnabled = enabled };
    }

    private async Task HandleSaveAppearance(AppearanceSettings updated)
    {
        await SettingsService.SaveAppearanceAsync(updated);
        _appearance = updated;
    }
}

.settings-layout {
    display: flex;
    gap: 1.5rem;
    min-height: 70vh;
}

.settings-nav {
    flex: 0 0 220px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

/* Sidebar styling */
::deep .settings-sidebar {
    background: #f8f9fa;
    border-radius: 0.5rem;
    padding: 0.5rem 0;
    position: sticky;
    top: 4.5rem;
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-nav {
        flex: none;
    }

    ::deep .settings-sidebar {
        position: static;
    }

    ::deep .settings-sidebar .nav {
        flex-direction: row !important;
        overflow-x: auto;
    }

    ::deep .settings-sidebar .nav-link {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
    }

    ::deep .settings-sidebar .nav-link.active {
        border-left-color: transparent;
        border-bottom-color: #0d6efd;
    }
}

