toolArgs.file_text:
.settings-layout {
    display: flex;
    gap: 1.5rem;
    min-height: 70vh;
}

.settings-nav {
    flex: 0 0 220px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

/* Sidebar styling */
::deep .settings-sidebar {
    background: #f8f9fa;
    border-radius: 0.5rem;
    padding: 0.5rem 0;
    position: sticky;
    top: 4.5rem;
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-nav {
        flex: none;
    }

    ::deep .settings-sidebar {
        position: static;
    }

    ::deep .settings-sidebar .nav {
        flex-direction: row !important;
        overflow-x: auto;
    }

    ::deep .settings-sidebar .nav-link {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
    }

    ::deep .settings-sidebar .nav-link.active {
        border-left-color: transparent;
        border-bottom-color: #0d6efd;
    }
}

